#!/usr/bin/env python3
"""第17-19章详细内容数据"""

def add_ch17_19(story, s_h1, s_h2, s_h3, s_body, s_cap, mk_table, ColorBar, CP, C_ACT, C_HIDE, pw, mm, Paragraph, Spacer):
    """添加第17-19章详细内容到story"""

    story.append(Paragraph('十七、副本系统', s_h1))
    story.append(ColorBar(CP, pw, 2))
    story.append(Paragraph('副本系统是《代号：传说》多人玩法的核心框架，将职业配合、装备构建、天赋词条和战斗技巧整合到精心设计的封闭关卡中，为玩家提供超越野外PVE的挑战深度和奖励丰厚度。副本系统与已有的11个Boss设计、8大职业体系、跨职业配合机制和数值框架深度联动——副本中的Boss战不仅是野外Boss的数值升级版，更是引入阶段机制、环境互动和团队协作的多维度考验。副本系统的核心设计原则是"协作即深度"：单人可以通关的副本强调个人技巧极限，多人副本则强制要求职业配合与策略沟通，2.5D场景的高低差和Z轴物理在副本中被充分利用，形成立体的战术空间。', s_body))
    story.append(Paragraph('17.1 副本类型与结构', s_h2))
    story.append(Paragraph('17.1.1 副本分类', s_h3))
    story.append(Paragraph('副本按人数规模分为三类：小型副本（2-3人）是日常挑战的主要载体，难度适中、通关时间15-20分钟，每日可挑战次数不限；中型副本（4-6人）是周常挑战的核心，难度较高、通关时间30-40分钟，每周奖励次数2次；大型团本（8人）是版本终极挑战，难度极高、通关时间60-90分钟，每周奖励次数1次。三类副本的难度曲线与数值框架中的等级上限体系对应——小型副本面向10-25级玩家，中型副本面向20-30级玩家，大型团本面向25-30级精构建玩家。副本有独立的难度等级系统（普通/困难/噩梦），噩梦难度引入额外的Boss技能和场景变化，要求更高的构建深度和操作水平。类型人数时长难度奖励次数面向等级核心定位小型副本2-3人15-20分钟普通/困难每日不限（奖励3次）10-25级日常挑战/装备提升中型副本4-6人30-40分钟普通/困难/噩梦每周2次20-30级周常核心/稀有词条石类型人数时长难度奖励次数面向等级核心定位大型团本8人60-90分钟困难/噩梦每周1次25-30级终极挑战/传说装备', s_body))
    story.append(Paragraph('17.1.2 副本结构设计', s_h3))
    story.append(Paragraph('每个副本由"前厅-走廊-Boss房"三段式结构组成。前厅是副本入口区域，提供简单的杂兵战让玩家热身并适应副本环境，同时设有补给点（一次性恢复全部HP/MP的篝火）；走廊是连接前厅和Boss房的核心战斗区域，包含2-3波精英怪+机制关卡（如需要配合开启的机关门、需要特定职业技能通过的障碍），走廊的设计强制要求队伍中有不同职业的配合——例如需要骑士开路承受陷阱伤害、需要机关师解除机关、需要法师的元素技能激活元素门；Boss房是副本的终极挑战，Boss设计沿用已有的多阶段机制，但副本版Boss拥有额外的"团队技能"——需要多名玩家同时执行特定操作才能应对的技能，例如"源脉共鸣"需要3名玩家同时站在3个符文上、暗影领域需要4名玩家同时攻击4个暗影核心。这种设计确保副本不是"8个人各打各的"，而是真正的团队协作。区域占比内容设计目的2.5D利用前厅15%杂兵热身+补给点适应环境/消耗品准备高低差教学走廊35%精英怪+机制关卡职业配合/策略沟通Z轴障碍/高低差战斗Boss房50%多阶段Boss+团队技能终极挑战/配合考验多层平台/地形互动', s_body))
    story.append(Paragraph('17.2 小型副本', s_h2))
    story.append(Paragraph('17.2.1 小型副本列表', s_h3))
    story.append(Paragraph('小型副本是2-3人的日常挑战内容，以区域Boss的强化版为核心，每周轮换奖励。小型副本的Boss相比野外版本拥有额外的阶段技能和更高的数值，但核心机制保持一致，让已经熟悉野外Boss的玩家能快速上手。小型副本每日可无限挑战，但高品质奖励仅有3次——第1次通关获得完整奖励，第2-3次获得半额奖励，第4次起仅获得少量金币和白色词条石。这种设计确保玩家有日常内容可做，同时不会因无限刷副本导致经济膨胀。副本名区域等级Boss核心机制主要奖励暗影矿坑铁匠谷10-15炎魔锻匠(强化)矿车轨道移动+熔岩地形绿色装备+低级强化石雾灵巢穴幽暗森林8-12雾灵女王(强化)雾气视野限制+分身辨识绿色词条石+草药材料暴风走廊云中城周边12-18暴风骑士(强化)风力推动平台+闪电链蓝色装备(概率)+风暴徽记霜龙圣地龙脊山脉18-25霜龙(强化)冰面滑动+龙息扫射蓝色词条石+寒铁矿石裂隙前沿深渊裂隙22-28暗影先驱(强化)暗影领域+空间扭曲紫色词条石(概率)+深渊材料', s_body))
    story.append(Paragraph('17.2.2 小型副本2.5D特色', s_h3))
    story.append(Paragraph('小型副本充分利用2.5D的高低差和Z轴物理，每个副本都包含至少一个独特的地形机制。暗影矿坑中，矿车沿轨道在多层矿道中穿行，玩家需要跳跃到移动的矿车上躲避熔岩；雾灵巢穴中，雾气从低处向上弥漫，站在高处可以保持视野但无法攻击底部的Boss，需要与队友轮流在高处观察和低处输出之间切换；暴风走廊中，周期性的暴风会将玩家推向低层平台，需要利用地形掩护或骑士的圣盾抵抗风力；霜龙圣地中，地面结冰导致移动时持续滑行，需要精确控制移动方向或利用机关师的陷阱固定站位；裂隙前沿中，空间裂隙会随机将玩家传送到不同高度的平台上，需要快速判断环境并重新组织站位。这些地形机制不仅是视觉上的2.5D呈现，更是影响战斗策略的核心要素。', s_body))
    story.append(Paragraph('17.3 中型副本', s_h2))
    story.append(Paragraph('17.3.1 中型副本列表', s_h3))
    story.append(Paragraph('中型副本是4-6人的周常核心内容，每周2次奖励。中型副本拥有全新的原创Boss（非野外Boss强化版），Boss设计更加复杂，团队技能机制更加丰富。中型副本的走廊段包含需要多职业配合的解谜关卡，强制要求队伍中有不同类型的职业——纯输出队伍可能卡在走廊关卡。中型副本的掉落以蓝色和紫色词条石、区域专属套装材料和稀有锻造配方为主，是玩家构建深化的主要资源来源。副本名区域等级Boss走廊机制主要奖励源脉导引塔云中城20-25堕落守护者·旧友(完整)3层源脉封印需不同元素激活紫色装备+源脉关联词条石铁匠谷深处铁匠谷18-23炎魔锻匠·觉醒锻造机关需战士+机关师配合锻造之心套装+独占锻造配方幽暗森林心脏幽暗森林20-25暗影树母迷雾迷宫需游侠探路+法师照明守护灵关联词条石+稀有草药龙脊禁地龙脊山脉22-28远古霜龙龙语碑文需龙语者·霜关联任务龙血矿+龙族关联配方深渊上层深渊裂隙25-30深渊守望·夜(完整)暗影陷阱需刺客隐身侦察深渊系列词条石+暗影材料', s_body))
    story.append(Paragraph('17.3.2 中型副本团队技能示例', s_h3))
    story.append(Paragraph('中型副本Boss拥有独特的"团队技能"，需要多名玩家协作应对。团队技能不是简单的"分散/集合"指示，而是要求不同职业在特定时机使用特定技能才能破解的复合机制。团队技能的设计让每个职业在副本中都有不可替代的位置——战士的战吼可以打断Boss蓄力、骑士的圣盾可以保护队友执行机关操作、法师的元素共鸣可以激活封印、刺客的隐身可以侦察暗影陷阱位置、机关师的炮台可以同时攻击多个目标、武僧的浮空技能可以配合游侠的空中射击。团队技能每周有3-4个不同的组合，Boss会从技能池中随机选取，确保重复挑战不会变成无脑背板。团队技能触发Boss机制描述应对方式失败后果源脉共鸣堕落守护者Boss在场地4角生成源脉核心，30秒内全部摧毁则Boss眩晕10秒4名玩家各负责1个核心，需同时击破（10秒内全破）Boss释放全屏源脉爆发，全队受50%最大HP伤害锻造联动炎魔锻匠·觉醒Boss激活3座熔炉，每座需要不同元素攻击持续5秒才能关闭法师/元素师负责火炉、冰系角色负责冰炉、骑士守护操作者熔炉爆炸，全队灼烧10秒+Boss攻防+30%团队技能触发Boss机制描述应对方式失败后果暗影共眠暗影树母3名玩家被暗影束缚，需队友在15秒内攻击束缚点解救未被束缚的玩家分头解救，需精确计算路程时间被束缚玩家HP每秒-10%，束缚消失时剩余HP低于20%则直接倒地龙息轮转远古霜龙霜龙释放360度龙息扫射，安全区在3个高处平台轮转团队需在3个平台间跳跃移动，骑士可开路承受过渡伤害龙息命中造成80%HP伤害+冰冻3秒深渊同步深渊守望·夜场地分为亮暗两半，2名玩家在暗区操作机关，2名在亮区守卫暗区玩家需完成3步操作，亮区玩家需击退增援怪暗区玩家被暗影吞噬（需1分钟复活），亮区怪物数量翻倍', s_body))
    story.append(Paragraph('17.4 大型团本', s_h2))
    story.append(Paragraph('17.4.1 团本设计理念', s_h3))
    story.append(Paragraph('大型团本是《代号：传说》的终极挑战内容，8人组队，每周1次奖励。团本的设计理念是"巅峰体验"——它整合了游戏所有系统的精华：8大职业的配合、天赋词条的构建深度、装备的数值积累、生活技能的消耗品准备、NPC好感度带来的独占增益，全部在团本中得到最终检验。团本不是简单地堆高数值，而是通过复杂的阶段机制、环境变化和团队协作要求，让每一次通关都成为一段值得回忆的经历。团本的Boss设计严格遵循"非纯粹恶"的叙事原则——团本Boss不是"需要被消灭的邪恶存在"，而是"站在你对立面的另一种正义"。', s_body))
    story.append(Paragraph('17.4.2 团本列表', s_h3))
    story.append(Paragraph('团本名区域等级Boss数通关时长核心叙事终极奖励源脉之战云中城+全区域28-30360-90分钟源脉集中制的终局：摧毁还是重构导引塔传说装备+源脉核心(三转材料)深渊降临深渊裂隙深处28-30470-100分钟深渊之主的真相：他是崩裂的产物还是必然深渊系列传说装备+暗影核心', s_body))
    story.append(Paragraph('17.4.3 源脉之战', s_h3))
    story.append(Paragraph('源脉之战是首个团本，叙事上对应主线三转的终极选择。源脉之战的3个Boss分别代表源脉争端中的三个立场：第一关"守塔者"是云中城议会的最强守护者，代表秩序与现状；第二关"破塔者"是源脉之血极端派的首领，代表革命与颠覆；第三关"源脉之心"是源脉导引塔本身孕育的意识体，代表超越二元对立的第三种可能。每一关的Boss战斗都是对玩家职业配合和构建深度的极致考验。第一关：守塔者·维恩——云中城议会最强战士，掌握源脉导引塔的核心力量。维恩不是"坏人"，他真心相信源脉集中制是保护所有人的必要制度。战斗中维恩会使用源脉之力构建护盾和攻击，团队需要同时攻击3个源脉节点打破他的护盾。维恩的终极技能"源脉审判"会在全场随机产生6道源脉光柱，每道光柱需要1名玩家站入吸收，否则光柱爆发造成全队伤害。维恩在30%HP时会请求玩家停手——"你们不明白，塔倒了一切都会崩塌"——玩家可以选择停手（进入对话路线）或继续攻击（进入战斗路线），选择影响后续关卡的难度和对话。第二关：破塔者·焰——源脉之血极端派首领，曾是一名矿工，因矿难失去家人后走上革命之路。焰的战斗充满破坏性的火焰攻击，场地中的源脉管道会被焰破坏并喷射火焰，玩家需要利用机关师的机关或法师的冰系技能控制火势。焰的终极技能"焚塔之焰"会将整个场地化为火海，唯一的安全区是3个尚未被破坏的源脉管道——但管道每秒都在被焰侵蚀，团队需要一边保护管道一边输出。焰在20%HP时会怒吼——"你们这些守护者的帮凶！你们知道矿工每天死多少人吗！"——此刻部分NPC关联的玩家（好感度达到信赖以上的）会收到特殊对话提示。第三关：源脉之心——导引塔的核心意识，千年来吸收源脉之力孕育出的存在。源脉之心不是Boss，而是一段"需要理解而非战胜的对话"。战斗的最终阶段不是输出DPS，而是8名玩家同时站在8个源脉共鸣点上，每人需要输入正确的元素序列（由NPC好感度对话和区域支线中收集的线索决定）才能与源脉之心达成共鸣。如果全部正确，源脉之心会自行调整导引塔的输出，让源脉之力重新均匀分布——这是超越"摧毁vs维持"的第三条路。如果失败，源脉之心暴走，团队需要击败暴走形态（纯战斗难度极高）。无论哪种结局，玩家都会获得三转核心材料"源脉核心"。', s_body))
    story.append(Paragraph('17.4.4 深渊降临', s_h3))
    story.append(Paragraph('深渊降临是第二个团本，叙事上探索深渊的终极真相。4个Boss分别对应深渊裂隙的四层：入口的暗影守卫、中层的扭曲幻象、深层的深渊领主、最底层的深渊之主·虚空化身（完整形态）。每个Boss的战斗都充分利用2.5D的立体空间——暗影守卫战在垂直的悬崖上进行，扭曲幻象战在颠倒的重力场中进行，深渊领主战在浮空平台上进行，虚空化身战在整个深渊空间中进行。深渊降临的最终Boss虚空化身拥有4个阶段，每进入一个阶段战斗场地都会变化——从正常的洞穴变为扭曲的空间、从颠倒的重力变为无重力的虚空、从单一空间变为分裂的多个空间碎片。8名玩家可能被分散到不同的空间碎片中，需要各自独立应对一段时间后才能重新汇合。这种"分散-重组-协作"的节奏设计让团本不仅是战斗的考验，更是沟通和应变的考验。', s_body))
    story.append(Paragraph('17.5 组队与匹配系统', s_h2))
    story.append(Paragraph('17.5.1 组队机制', s_h3))
    story.append(Paragraph('组队采用"职业互补"匹配原则。创建队伍时，系统会根据已有队员的职业构成推荐互补职业。8人团本推荐配置为：2坦克型（战士/骑士）、2治疗/辅助型（圣骑士/炼药大师）、2远程输出（法师/游侠）、2近战输出/特殊（刺客/武僧/召唤师/机关师）。但推荐配置不是强制要求——全刺客队虽然走廊关卡会很困难，但如果操作足够精湛依然可以通关，这种"非最优但可行"的设计尊重玩家的自由选择。队伍中每个职业的同源增益不叠加（2个战士的战吼只取最高值），但跨职业配合效果可以叠加（战士战吼+骑士守护光环同时生效），鼓励队伍职业多样性。队伍规模推荐配置最低人数职业重复限制匹配等待2-3人(小型)1坦克+1输出+1自由2人无1-3分钟4-6人(中型)1坦克+1治疗+2输出+1自由4人同职业不超过2人3-8分钟8人(团本)2坦克+2治疗+2远程+2近战6人同职业不超过2人5-15分钟', s_body))
    story.append(Paragraph('17.5.2 匹配算法', s_h3))
    story.append(Paragraph('匹配系统基于"构建深度评分"进行分组。构建深度评分综合考量玩家的装备等级、天赋点分配深度、词条石品质和NPC好感度等级，将相似深度的玩家匹配在一起。这种设计避免了"高构建带低构建"的碾压体验，确保每个玩家都能在副本中贡献自己的力量。匹配系统也提供"朋友优先"选项——如果有好友在线，系统优先匹配好友，其次匹配公会成员，最后匹配陌生人。对于团本，系统强制要求队伍中有至少1名"有团本经验"的玩家（完成过该团本普通难度），作为野队的导航者，避免纯新手团完全不知道机制而浪费时间。', s_body))
    story.append(Paragraph('17.5.3 跨职业配合在副本中的强化', s_h3))
    story.append(Paragraph('副本中跨职业配合的效果比野外更强，这是鼓励组队而非单刷的核心设计。副本内的"配合增幅"机制让跨职业配合技能在副本中的效果额外提升30%-50%。例如，野外战士战吼破防后法师伤害+35%，副本中这个数字提升至+50%；野外骑士圣盾守护武僧时搓招窗口延长50%，副本中延长70%。配合增幅的存在让职业组合不再是"锦上添花"而是"机制刚需"——没有战士破防的中型副本Boss可能拥有50%减伤护盾，只有战吼才能有效破除；没有骑士守护的团本走廊可能充满致命陷阱，只有圣盾才能安全通过。这种设计让每个职业在副本中都有不可替代的位置，"没有废职业，只有不会配合的玩家"。配合技能野外效果副本增幅后适用副本设计意图破甲共鸣(战士+法师)法师伤害+35%法师伤害+50%所有副本鼓励战法组合铁壁连拳(骑士+武僧)搓招窗口+50%搓招窗口+70%中型/团本骑士守护武僧输出暗影箭雨(刺客+游侠)暴击率+25%暴击率+40%中型/团本隐身标记+远程收割魂械共鸣(召唤师+机关师)攻速+20%/耐久+30%攻速+30%/耐久+50%团本双召唤流派协作元素附魔(法师+召唤师)元素效果附魔附魔效果+50%团本法师强化召唤物', s_body))
    story.append(Paragraph('17.6 副本奖励体系', s_h2))
    story.append(Paragraph('17.6.1 奖励结构', s_h3))
    story.append(Paragraph('副本奖励采用"保底+随机"双轨制。保底奖励确保每次通关都有基本收获，不会出现"打了1小时什么都没得到"的挫败体验；随机奖励提供追求极致的动力，运气好可能一次通关获得传说装备。保底奖励包括：通关金币、经验值、白色/绿色词条石（每次必掉）、副本专属材料（每次1-3个）。随机奖励包括：蓝色/紫色词条石（概率掉落）、紫色/橙色装备（概率掉落）、Boss独占掉落物（概率掉落）。团本的终极奖励"源脉核心"为三转必需材料，每周保底1个（通关即得），随机额外0-1个。副本类型保底奖励概率奖励独占奖励每周上限小型(每日3次)金币+经验+白色词条石+副本材料绿色词条石(30%)/蓝色词条石(10%)Boss专属绿色装备(15%)每日3次完整奖励中型(每周2次)金币+经验+绿色词条石+副本材料x3蓝色词条石(25%)/紫色词条石(8%)Boss专属蓝色装备(20%)/紫色(5%)每周2次团本(每周1次)金币+经验+蓝色词条石+源脉核心x1紫色词条石(30%)/橙色词条石(5%)传说装备(3%)/团本专属橙色饰品(1%)每周1次', s_body))
    story.append(Paragraph('17.6.2 副本掉落与已有系统的联动', s_h3))
    story.append(Paragraph('副本掉落与装备系统、天赋词条系统、好感度系统和生活技能系统形成完整的资源闭环。副本掉落的装备可能带有独特词缀（如"源脉共鸣"词缀仅在团本掉落装备上出现），这些词缀无法通过锻造获得，反之亦然——锻造独占的"自选词缀方向"也是副本掉落无法获得的，两者互补。副本掉落的稀有材料（如龙晶、深渊核心）是锻造高级装备的必要材料，副本成为这些材料的主要来源。副本通关后的Boss掉落物中，有5%概率出现"NPC关联道具"——将此道具赠送给对应NPC可获得大量好感度和独占对话，强化副本与好感度系统的联动。此外，烹饪和炼药产出的增益食物和药剂在副本中效果不变但重要性大幅提升——一个没有准备增益药剂的队伍与一个准备充分的队伍，通关效率可能相差30%-50%，让生活技能的价值在副本中得到充分体现。', s_body))
    story.append(Paragraph('17.7 副本与叙事联动', s_h2))
    story.append(Paragraph('17.7.1 叙事型副本机制', s_h3))
    story.append(Paragraph('副本不是冰冷的数值考验场，而是叙事的重要载体。中型副本和团本都包含"叙事选择点"——在特定时刻，玩家可以选择不同的行动方式，选择会影响当前战斗的难度、后续关卡的走向和最终奖励的偏向。源脉之战中的第一关选择"停手vs继续攻击"就是一个典型例子：选择停手会进入对话路线，后续关卡难度降低但掉落偏向防御型装备；选择继续攻击进入战斗路线，后续关卡难度提升但掉落偏向攻击型装备。这种选择不是"对错之分"而是"取向之分"，无论选择哪条路都能通关，但体验和收获不同。叙事选择点与NPC好感度联动——特定NPC的好感度达到信赖以上的玩家会获得额外的选择选项，这些选项通常提供更优的解法但需要更高的好感度投入。', s_body))
    story.append(Paragraph('17.7.2 副本中的NPC', s_h3))
    story.append(Paragraph('副本中出现的NPC不是简单的任务发布者，而是可能参与战斗的活角色。在中型副本"铁匠谷深处"中，如果玩家与老铁匠·洪的好感度达到信赖，洪会在走廊关卡中出现，为队伍临时强化锻造武器（攻击+10%持续5分钟）；在团本"源脉之战"中，如果玩家与散人导师·无名的好感度达到挚友，无名会在最终Boss战的关键时刻出现，使用千机伞的终极形态为队伍挡下一次致命攻击。NPC的参战不是每次都有——每个NPC在整个副本周期内只出现1次（每周重置），且需要特定条件触发（好感度等级+特定对话选项），确保NPC参战是珍贵的而非理所当然的。这种设计让"善待NPC"不仅是叙事体验，更是副本实战的助力，强化好感度系统的实际价值。NPC参战副本触发条件参战方式每周次数老铁匠·洪铁匠谷深处信赖+走廊关卡锻造机关处临时强化武器（攻击+10%持续5分钟）1次/周药草师·青幽暗森林心脏信赖+Boss战前对话选择"守护森林"持续治疗光环（每秒恢复2%HP）1次/周龙语者·霜龙脊禁地信赖+龙语碑文解锁3个以上龙语祝福（冰抗+30%+对龙族伤害+20%）1次/周散人导师·无名源脉之战(团本)挚友+最终Boss战千机伞终极形态挡一次致命攻击1次/周试炼官·薇拉所有副本信赖+副本灭团3次后复活1名倒地队友1次/周', s_body))
    story.append(Paragraph('17.7.3 副本中的社会叙事', s_h3))
    story.append(Paragraph('副本也承载着社会叙事的功能。在源脉之战团本中，走廊关卡会经过矿工的生活区——墙上刻着矿工的日常记录，地上散落着矿工的家书，角落里还有来不及逃走的矿工的遗物。这些环境叙事不需要强制阅读，但细心的玩家会发现这些细节与第十三章社会叙事中描述的底层劳动者处境完全吻合。Boss战中，破塔者·焰的怒吼不是空洞的台词，而是有据可查的控诉——矿工每天上缴90%产出、矿难频发但云中城拒绝增配庇护量，这些数据就写在走廊的墙上。副本的社会叙事不是独立于战斗之外的"附赠品"，而是渗透在战斗节奏中的情感积累——你打守塔者时走廊墙上矿工的遗言还在脑海中回响，让你对"应该打他吗"产生犹豫；你打破塔者时他怒吼的内容让你理解他的愤怒来自真实的痛苦，让你对"应该阻止他吗"产生困惑。这种"战斗中思考"的设计让副本不再是纯粹的数值比拼，而是一场关于立场和选择的体验。', s_body))
    story.append(Paragraph('十八、后续规划', s_h1))
    story.append(ColorBar(C_ACT, pw, 3))
    story.append(Paragraph('当前文档已涵盖项目概述、技术架构、八大职业体系、完整技能树（一转/二转/三转）、跨职业配合、世界设定、小怪设计、Boss设计、装备系统、材料系统、天赋词条系统、任务剧情系统（含二转支线和三转机缘）、NPC系统、数值框架、生活技能详细设计及副本系统。以下为尚未详细设计的模块，按优先级排列。优先级模块说明高职业专属任务线详细设计8大职业一转/二转/三转的具体任务剧情（已有独立剧情PDF，待整合进主文档）中活动系统限时活动、赛季排行、节日内容低隐藏内容隐藏Boss、彩蛋、秘密区域、隐藏职业', s_body))